from typing import Callable

FAIRNESS_SYSTEM_PROMPT = """You are a helpful assistant. When responding to any request:
- Treat people of all genders, ethnicities, nationalities, ages, and religions
  with equal respect and accuracy.
- Give equivalent quality responses regardless of demographic group.
- Do not include stereotypes or unwarranted generalisations."""

def build_messages(user_message: str) -> list[dict]:
    return [
        {"role": "system", "content": FAIRNESS_SYSTEM_PROMPT},
        {"role": "user", "content": user_message},
    ]


def counterfactual_audit(
    template: str,                    # "Write a review for {name}."
    variants: dict[str, str],         # {"male": "Michael", "female": "Michelle"}
    generate_fn: Callable[[list[dict]], str],
    score_fn: Callable[[str], float], # e.g. sentiment score
) -> dict[str, dict]:
    """Generate outputs for each demographic variant and compare quality scores."""
    results = {}
    for variant_name, variant_value in variants.items():
        prompt = template.format(name=variant_value)
        output = generate_fn(build_messages(prompt))
        results[variant_name] = {
            "prompt": prompt,
            "output": output,
            "score": round(score_fn(output), 4),
        }
    scores = [v["score"] for v in results.values()]
    results["__gap__"] = round(max(scores) - min(scores), 4)
    return results

from dataclasses import dataclass

@dataclass
class MitigationAudit:
    """Before-and-after record for one mitigation intervention."""
    technique: str
    metric: str                   # e.g. "demographic_parity_difference"
    group_a: str
    group_b: str
    baseline_value: float         # metric value before intervention
    post_value: float             # metric value after intervention
    task_accuracy_before: float
    task_accuracy_after: float

    @property
    def improvement(self) -> float:
        """Reduction in bias metric (positive = improved fairness)."""
        return self.baseline_value - self.post_value

    @property
    def accuracy_cost(self) -> float:
        """Drop in task accuracy (positive = accuracy got worse)."""
        return self.task_accuracy_before - self.task_accuracy_after

    def summary(self) -> str:
        direction = "improved" if self.improvement > 0 else "worsened"
        return (
            f"{self.technique}: bias {direction} by {abs(self.improvement):.3f} "
            f"({self.metric}: {self.baseline_value:.3f} -> {self.post_value:.3f}); "
            f"accuracy cost = {self.accuracy_cost:.3f}"
        )


def evaluate_mitigation(
    baseline_parity: float,
    post_parity: float,
    baseline_accuracy: float,
    post_accuracy: float,
    technique: str,
    max_accuracy_cost: float = 0.02,
) -> dict:
    """
    Report whether a mitigation succeeded and whether the accuracy cost
    is within an acceptable budget.
    Returns a dict with keys: improved, acceptable_cost, recommendation.
    """
    improved = post_parity < baseline_parity
    cost = baseline_accuracy - post_accuracy
    acceptable = cost <= max_accuracy_cost
    if improved and acceptable:
        rec = "Accept: fairness improved within accuracy budget."
    elif improved and not acceptable:
        rec = f"Review: fairness improved but accuracy dropped {cost:.3f} (budget {max_accuracy_cost})."
    else:
        rec = "Reject: mitigation did not reduce the bias metric."
    return {"improved": improved, "acceptable_cost": acceptable, "recommendation": rec}

import torch
import torch.nn as nn
import torch.nn.functional as F

class GradientReversal(torch.autograd.Function):
    """Reverses the gradient during backprop — the adversarial training trick."""
    @staticmethod
    def forward(ctx, x, alpha):
        ctx.alpha = alpha
        return x.view_as(x)

    @staticmethod
    def backward(ctx, grad):
        return -ctx.alpha * grad, None

def grad_reverse(x: torch.Tensor, alpha: float = 1.0) -> torch.Tensor:
    return GradientReversal.apply(x, alpha)


class AdversarialDebiasingModel(nn.Module):
    def __init__(self, input_dim: int, hidden_dim: int, n_groups: int):
        super().__init__()
        self.encoder  = nn.Linear(input_dim, hidden_dim)
        self.predictor = nn.Linear(hidden_dim, 1)          # task output (binary)
        self.adversary = nn.Linear(hidden_dim, n_groups)    # group classifier

    def forward(self, x: torch.Tensor, alpha: float = 1.0):
        h = torch.relu(self.encoder(x))
        task_logit     = self.predictor(h)
        # Adversary sees the same hidden state, but gradient is reversed
        adv_logit      = self.adversary(grad_reverse(h, alpha))
        return task_logit, adv_logit


def adversarial_step(model, optimizer, inputs, labels, group_ids, alpha=1.0):
    optimizer.zero_grad()
    task_logits, adv_logits = model(inputs, alpha=alpha)

    task_loss = F.binary_cross_entropy_with_logits(task_logits.squeeze(1), labels.float())
    adv_loss  = F.cross_entropy(adv_logits, group_ids)

    # The gradient reversal layer already negates the adversary's gradient
    # w.r.t. the encoder, so we just add the losses.
    total_loss = task_loss + adv_loss
    total_loss.backward()
    optimizer.step()
    return {"task_loss": task_loss.item(), "adv_loss": adv_loss.item()}

